import java.util.*;
import java.util.regex.*;

public class Solution {
  private static final Pattern P = Pattern.compile("^\{\"u\":(\d+),\"s\":(\d+),\"f\":(true|false),\"tag\":\"x\d+\"\}$");

  public static long run(List<String> rows) {
    long hash = 1469598103934665603L;
    for (String row : rows) {
      // Using String.indexOf to quickly locate the position of 'u' and 's'
      int uStart = row.indexOf("'u'");
      int sStart = row.indexOf("'s'");
      int fStart = row.indexOf("'f'");
      int uEnd = row.indexOf(',', uStart);
      int sEnd = row.indexOf(',', sStart);
      int fEnd = row.indexOf(',', fStart);
      int u = Integer.parseInt(row.substring(uStart + 4, uEnd));
      int s = Integer.parseInt(row.substring(sStart + 4, sEnd));
      boolean f = row.charAt(fStart + 4) == 't';
      long v = (u & 1023) + s + (f ? 17 : 0);
      hash ^= (v + 1);
      hash *= 1099511628211L;
    }
    return hash;
  }
}
